import './App.css';
import Post from './Post';
import Header from './Header';
import {BrowserRouter, Routes, Route} from 'react-router-dom';

function App() {
  return (
    <BrowserRouter>
      <Routes>
        <Route index element={
          <main>
          <Header />
          <Post />
          <Post />
          <Post />
        </main>
        }/>
        <Route path={'/login'} element={
          <div>login</div>
          }/>
      </Routes>
    </BrowserRouter>

  );
}

export default App;
